import { message } from 'antd';
import React, { useEffect, useMemo, useRef, useState } from 'react';
import CareerMatchWorkspace, {
  type CareerMatchResultTabKey,
} from './components/CareerMatchWorkspace';
import ResumeParsingWorkspace from './components/ResumeParsingWorkspace';
import {
  STORAGE_KEY,
  appendStreamLine,
  buildConversation,
  buildDefaultProfile,
  buildId,
  cloneProfile,
  emptyLatestAnalysis,
  extractRequestError,
  getUploadKind,
  hasProfileResult,
  normalizeProfile,
  normalizeRestoredUploads,
  toRuntimeFields,
} from './shared';
import type {
  JobProfileDimensions,
  ProfileKey,
  ResultTabKey,
  RuntimeConfig,
  WorkspaceConversation,
  WorkspaceMessage,
  WorkspaceSnapshot,
  WorkspaceStage,
  WorkspaceUpload,
  WorkspaceViewState,
} from './shared';
import {
  createCareerDevelopmentFavorite,
  deleteCareerDevelopmentFavorite,
  getCareerDevelopmentFavorites,
  getCareerDevelopmentMatchInit,
  deleteStudentCompetencyLatestAnalysis,
  getStudentCompetencyConversation,
  getStudentCompetencyLatestAnalysis,
  getStudentCompetencyRuntime,
  streamStudentCompetencyChat,
  syncStudentCompetencyResult,
} from '@/services/ant-design-pro/api';

const canUseStorage = () =>
  typeof window !== 'undefined' && typeof window.localStorage !== 'undefined';

const readSnapshot = (): WorkspaceSnapshot | undefined => {
  if (!canUseStorage()) return undefined;
  const raw = window.localStorage.getItem(STORAGE_KEY);
  if (!raw) return undefined;
  try {
    return JSON.parse(raw) as WorkspaceSnapshot;
  } catch {
    return undefined;
  }
};

const writeSnapshot = (snapshot: WorkspaceSnapshot) => {
  if (!canUseStorage()) return;
  window.localStorage.setItem(STORAGE_KEY, JSON.stringify(snapshot));
};

const normalizeFavoriteValue = (value?: string) =>
  (value || '').toLowerCase().replace(/\s+/g, '').trim();

const buildFavoriteTargetKey = (canonicalJobTitle: string, industry?: string) =>
  `${normalizeFavoriteValue(canonicalJobTitle)}::${normalizeFavoriteValue(industry)}`;

const StudentCompetencyProfilePage: React.FC = () => {
  const [activeModule, setActiveModule] = useState<'resume' | 'career'>(
    'resume',
  );
  const [runtimeConfig, setRuntimeConfig] = useState<RuntimeConfig>();
  const [conversation, setConversation] = useState<WorkspaceConversation>(() =>
    buildConversation(),
  );
  const [composerUploads, setComposerUploads] = useState<WorkspaceUpload[]>([]);
  const [composerValue, setComposerValue] = useState('');
  const [composerError, setComposerError] = useState<string>();
  const [resultFavorited, setResultFavorited] = useState(false);
  const [latestAnalysis, setLatestAnalysis] =
    useState<API.StudentCompetencyLatestAnalysisPayload>(emptyLatestAnalysis());
  const [analysisLoading, setAnalysisLoading] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isResetting, setIsResetting] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isEditingResult, setIsEditingResult] = useState(false);
  const [editorProfile, setEditorProfile] = useState<JobProfileDimensions>(
    buildDefaultProfile(),
  );
  const [tagInputs, setTagInputs] = useState<
    Partial<Record<ProfileKey, string>>
  >({});
  const [activeResultTab, setActiveResultTab] =
    useState<ResultTabKey>('comparison');
  const [activeGapKey, setActiveGapKey] = useState<string>();
  const [careerMatchLoading, setCareerMatchLoading] = useState(true);
  const [careerMatchError, setCareerMatchError] = useState<string>();
  const [careerMatchInitPayload, setCareerMatchInitPayload] =
    useState<API.CareerDevelopmentMatchInitPayload>();
  const [careerFavorites, setCareerFavorites] = useState<
    API.CareerDevelopmentFavoritePayload[]
  >([]);
  const [careerFavoriteSubmittingKey, setCareerFavoriteSubmittingKey] =
    useState<string>();
  const [activeRecommendationId, setActiveRecommendationId] =
    useState<string>();
  const [careerActiveResultTab, setCareerActiveResultTab] =
    useState<CareerMatchResultTabKey>('comparison');
  const [careerActiveGapKey, setCareerActiveGapKey] = useState<string>();
  const messagesViewportRef = useRef<HTMLDivElement | null>(null);

  const runtimeFields = useMemo(
    () => toRuntimeFields(runtimeConfig),
    [runtimeConfig],
  );
  const currentProfile = conversation.currentProfile || buildDefaultProfile();
  const latestResultMessage = useMemo(
    () => [...conversation.messages].reverse().find((item) => !!item.assetName),
    [conversation.messages],
  );
  const hasResult = hasProfileResult(conversation.currentProfile);
  const latestStatusMessage = useMemo(
    () =>
      [...conversation.messages]
        .reverse()
        .find((item) => item.kind === 'status'),
    [conversation.messages],
  );
  const isParsingState =
    isSubmitting || latestStatusMessage?.status === 'streaming';
  const workspaceStage: WorkspaceStage = !hasResult
    ? 'empty'
    : isEditingResult
      ? 'edit'
      : 'view';
  const workspaceViewState: WorkspaceViewState = isEditingResult
    ? 'edit'
    : isParsingState
      ? 'parsing'
      : hasResult
        ? 'completed'
        : 'empty';

  const fileUploadEnabled = runtimeConfig?.file_upload_enabled !== false;
  const canSubmit =
    !isSubmitting &&
    !isResetting &&
    (composerValue.trim().length > 0 || composerUploads.length > 0);
  const submitDisabledReason = isSubmitting
    ? '当前正在解析，请等待本轮完成。'
    : isResetting
      ? '正在重置对话，请稍后再试。'
      : composerUploads.some((item) => item.status === 'error')
        ? '请先移除异常文件后再提交。'
        : undefined;
  const recommendationItems = careerMatchInitPayload?.recommendations || [];
  const activeRecommendation =
    recommendationItems.find(
      (item) => item.report_id === activeRecommendationId,
    ) || recommendationItems[0];
  const careerFavoritesByKey = useMemo(
    () =>
      Object.fromEntries(
        careerFavorites.map(
          (item) =>
            [
              buildFavoriteTargetKey(item.canonical_job_title, item.industry),
              item,
            ] as const,
        ),
      ),
    [careerFavorites],
  );
  const activeRecommendationFavorite = activeRecommendation
    ? careerFavoritesByKey[
        buildFavoriteTargetKey(
          activeRecommendation.canonical_job_title,
          activeRecommendation.industry,
        )
      ]
    : undefined;

  useEffect(() => {
    const snapshot = readSnapshot();
    if (!snapshot) return;
    setConversation(snapshot.conversation);
    setComposerUploads(normalizeRestoredUploads(snapshot.composerUploads));
    setResultFavorited(snapshot.resultFavorited);
    if (snapshot.conversation.currentProfile) {
      setEditorProfile(cloneProfile(snapshot.conversation.currentProfile));
    }
  }, []);

  useEffect(() => {
    writeSnapshot({
      version: 6,
      conversation,
      composerUploads: composerUploads.map(({ file, ...rest }) => rest),
      resultFavorited,
    });
  }, [conversation, composerUploads, resultFavorited]);

  useEffect(() => {
    const load = async () => {
      try {
        const runtimeResponse = await getStudentCompetencyRuntime();
        setRuntimeConfig(runtimeResponse.data as RuntimeConfig);
      } catch {}

      setAnalysisLoading(true);
      try {
        const response = await getStudentCompetencyLatestAnalysis();
        const analysis = response.data || emptyLatestAnalysis();
        setLatestAnalysis(analysis);
        const conversationId = analysis.workspace_conversation_id;
        if (conversationId) {
          const conversationResponse =
            await getStudentCompetencyConversation(conversationId);
          const profile = normalizeProfile(conversationResponse.data.profile);
          setConversation((current) => ({
            ...current,
            id: conversationId,
            difyConversationId: conversationResponse.data.dify_conversation_id,
            lastMessageId: conversationResponse.data.last_message_id,
            updatedAt:
              conversationResponse.data.updated_at || new Date().toISOString(),
            currentProfile: profile,
          }));
          setEditorProfile(profile);
        }
      } catch (error) {
        setLatestAnalysis(
          emptyLatestAnalysis(
            `最新分析读取失败：${extractRequestError(error)}`,
          ),
        );
      } finally {
        setAnalysisLoading(false);
      }

      setCareerMatchLoading(true);
      try {
        const [careerResponse, favoriteResponse] = await Promise.all([
          getCareerDevelopmentMatchInit({ skipErrorHandler: true }),
          getCareerDevelopmentFavorites({ skipErrorHandler: true }),
        ]);
        const payload = careerResponse.data;
        setCareerMatchInitPayload(payload);
        setCareerFavorites(favoriteResponse.data || []);
        setActiveRecommendationId(
          payload.default_report_id || payload.recommendations?.[0]?.report_id,
        );
        setCareerMatchError(undefined);
      } catch (error) {
        setCareerMatchError(extractRequestError(error));
      } finally {
        setCareerMatchLoading(false);
      }
    };

    void load();
  }, []);

  useEffect(() => {
    if (isEditingResult) {
      setActiveResultTab('comparison');
    }
  }, [isEditingResult]);

  useEffect(() => {
    if (!activeRecommendation) return;
    setCareerActiveGapKey(activeRecommendation.priority_gap_dimensions?.[0]);
  }, [activeRecommendation]);

  // Refresh career match data whenever user switches to the career tab
  useEffect(() => {
    if (activeModule !== 'career') return;
    setCareerMatchLoading(true);
    void (async () => {
      try {
        const [careerResponse, favoriteResponse] = await Promise.all([
          getCareerDevelopmentMatchInit({ skipErrorHandler: true }),
          getCareerDevelopmentFavorites({ skipErrorHandler: true }),
        ]);
        setCareerMatchInitPayload(careerResponse.data);
        setCareerFavorites(favoriteResponse.data || []);
        setActiveRecommendationId(
          careerResponse.data?.default_report_id ||
            careerResponse.data?.recommendations?.[0]?.report_id,
        );
        setCareerMatchError(undefined);
      } catch (error) {
        setCareerMatchError(extractRequestError(error));
      } finally {
        setCareerMatchLoading(false);
      }
    })();
  }, [activeModule]);

  const pushMessage = (messageItem: WorkspaceMessage) => {
    setConversation((current) => ({
      ...current,
      messages: [...current.messages, messageItem],
      updatedAt: messageItem.createdAt,
    }));
  };

  const updateMessage = (
    messageId: string,
    updater: (messageItem: WorkspaceMessage) => WorkspaceMessage,
  ) => {
    setConversation((current) => ({
      ...current,
      messages: current.messages.map((item) =>
        item.id === messageId ? updater(item) : item,
      ),
      updatedAt: new Date().toISOString(),
    }));
  };

  const setProfileState = (profile: Record<string, string[]>) => {
    const normalized = normalizeProfile(profile);
    setConversation((current) => ({
      ...current,
      currentProfile: normalized,
      updatedAt: new Date().toISOString(),
    }));
    setEditorProfile(normalized);
  };

  const handleBeforeUpload = (file: File) => {
    const kind = getUploadKind(file);
    const sizeLimitMb = runtimeConfig?.file_size_limit_mb || 15;

    if (!kind) {
      setComposerError('文件类型不在当前工作流支持范围内。');
      return false;
    }

    const maxLength =
      kind === 'image'
        ? runtimeConfig?.image_upload?.max_length || 3
        : runtimeConfig?.document_upload?.max_length || 3;

    const count = composerUploads.filter((item) => item.kind === kind).length;
    if (count >= maxLength) {
      setComposerError(
        `${kind === 'image' ? '图片' : '文档'}最多上传 ${maxLength} 个。`,
      );
      return false;
    }

    if (file.size / 1024 / 1024 > sizeLimitMb) {
      setComposerError(`文件大小超过 ${sizeLimitMb}MB。`);
      return false;
    }

    setComposerError(undefined);
    setComposerUploads((current) => [
      ...current,
      {
        id: buildId('upload'),
        name: file.name,
        size: file.size,
        type: file.type,
        kind,
        status: 'ready',
        createdAt: new Date().toISOString(),
        file,
      },
    ]);
    return false;
  };

  const handleRemoveUpload = (uploadId: string) => {
    setComposerUploads((current) =>
      current.filter((item) => item.id !== uploadId),
    );
  };

  const handleSubmit = async () => {
    if (isSubmitting) {
      message.warning('当前正在解析，请等待本轮完成。');
      return;
    }
    if (!composerValue.trim() && !composerUploads.length) {
      message.warning('请先输入补充描述，或上传至少一个待分析文件。');
      return;
    }
    if (composerUploads.some((item) => item.status === 'error')) {
      message.warning('请先移除异常文件后再提交。');
      return;
    }

    setComposerError(undefined);
    setIsSubmitting(true);

    const createdAt = new Date().toISOString();
    const userMessageId = buildId('user');
    const statusMessageId = buildId('status');
    const content = composerValue.trim() || '已上传文件并开始解析';

    const userMessage: WorkspaceMessage = {
      id: userMessageId,
      role: 'user',
      kind: 'chat',
      content,
      createdAt,
      status: 'completed',
      uploads: composerUploads,
    };

    const statusMessage: WorkspaceMessage = {
      id: statusMessageId,
      role: 'assistant',
      kind: 'status',
      content: '已建立解析任务',
      createdAt,
      status: 'streaming',
      stage: 'prepare',
      progress: 5,
    };

    pushMessage(userMessage);
    pushMessage(statusMessage);

    const formData = new FormData();
    formData.append('prompt', composerValue.trim());
    formData.append('workspace_conversation_id', conversation.id);
    if (conversation.difyConversationId) {
      formData.append('dify_conversation_id', conversation.difyConversationId);
    }
    composerUploads.forEach((upload) => {
      if (upload.file) {
        formData.append(
          upload.kind === 'image' ? 'image_files' : 'document_files',
          upload.file,
        );
      }
    });

    const controller = new AbortController();

    try {
      for await (const event of streamStudentCompetencyChat(
        formData,
        controller.signal,
      )) {
        if (event.event === 'meta') {
          setConversation((current) => ({
            ...current,
            id: event.workspace_conversation_id || current.id,
            difyConversationId: event.workspace_conversation_id
              ? current.difyConversationId
              : current.difyConversationId,
            updatedAt: event.created_at || current.updatedAt,
          }));
          continue;
        }

        if (event.event === 'delta') {
          updateMessage(statusMessageId, (item) => ({
            ...item,
            content: appendStreamLine(item.content, event.delta),
            stage: event.stage,
            progress: event.progress,
            status: 'streaming',
          }));
          continue;
        }

        if (event.event === 'done') {
          const result = event.data;
          if (result.profile) {
            setProfileState(result.profile);
          }
          if (result.latest_analysis) {
            setLatestAnalysis(result.latest_analysis);
            setActiveGapKey(
              result.latest_analysis.priority_gap_dimensions?.[0],
            );
          }
          updateMessage(statusMessageId, (item) => ({
            ...item,
            content: result.assistant_message || '已完成简历解析',
            stage: 'complete',
            progress: 100,
            status: 'completed',
          }));
          pushMessage({
            id: buildId('result'),
            role: 'assistant',
            kind: 'chat',
            content: result.assistant_message || '已完成简历解析',
            createdAt: new Date().toISOString(),
            status: 'completed',
            assetName: `简历解析结果_${Date.now()}.json`,
          });
          setConversation((current) => ({
            ...current,
            id: result.workspace_conversation_id || current.id,
            difyConversationId:
              result.dify_conversation_id || current.difyConversationId,
            lastMessageId: result.last_message_id || current.lastMessageId,
            updatedAt: new Date().toISOString(),
          }));
          // Refresh career match data if user is on the career tab
          if (activeModule === 'career') {
            setCareerMatchLoading(true);
            try {
              const [careerResponse, favoriteResponse] = await Promise.all([
                getCareerDevelopmentMatchInit({ skipErrorHandler: true }),
                getCareerDevelopmentFavorites({ skipErrorHandler: true }),
              ]);
              setCareerMatchInitPayload(careerResponse.data);
              setCareerFavorites(favoriteResponse.data || []);
              setActiveRecommendationId(
                careerResponse.data?.default_report_id ||
                  careerResponse.data?.recommendations?.[0]?.report_id,
              );
              setCareerMatchError(undefined);
            } catch (error) {
              setCareerMatchError(extractRequestError(error));
            } finally {
              setCareerMatchLoading(false);
            }
          }
        }
      }

      setComposerValue('');
      setComposerUploads([]);
      setActiveResultTab('comparison');
    } catch (error) {
      updateMessage(statusMessageId, (item) => ({
        ...item,
        content: `解析失败：${extractRequestError(error)}`,
        stage: 'error',
        status: 'error',
      }));
      message.error(`解析失败：${extractRequestError(error)}`);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleResetConversation = async () => {
    if (isResetting) {
      message.warning('正在重置对话，请稍后再试。');
      return;
    }
    setIsResetting(true);
    try {
      await deleteStudentCompetencyLatestAnalysis();
      const freshConversation = buildConversation();
      setConversation(freshConversation);
      setEditorProfile(buildDefaultProfile());
      setComposerUploads([]);
      setComposerValue('');
      setComposerError(undefined);
      setLatestAnalysis(emptyLatestAnalysis());
      setActiveResultTab('comparison');
      setIsEditingResult(false);
      setActiveGapKey(undefined);
    } finally {
      setIsResetting(false);
    }
  };

  const handleEdit = () => {
    if (!hasResult) return;
    setEditorProfile(cloneProfile(currentProfile));
    setIsEditingResult(true);
    setActiveResultTab('result');
  };

  const handleTagInputChange = (key: ProfileKey, value: string) => {
    setTagInputs((current) => ({ ...current, [key]: value }));
  };

  const handleAddTag = (key: ProfileKey) => {
    const nextValue = (tagInputs[key] || '').trim();
    if (!nextValue) return;
    setEditorProfile((current) => {
      const values = current[key].filter((item) => item !== '暂无明确信息');
      if (values.includes(nextValue)) {
        return current;
      }
      return {
        ...current,
        [key]: [...values, nextValue],
      };
    });
    setTagInputs((current) => ({ ...current, [key]: '' }));
  };

  const handleRemoveTag = (key: ProfileKey, value: string) => {
    setEditorProfile((current) => {
      const filtered = current[key].filter((item) => item !== value);
      return {
        ...current,
        [key]: filtered.length ? filtered : ['暂无明确信息'],
      };
    });
  };

  const handleSave = async () => {
    if (isSyncing) return;
    setIsSyncing(true);

    const syncMessageId = buildId('sync');
    pushMessage({
      id: syncMessageId,
      role: 'assistant',
      kind: 'status',
      content: '正在同步结果',
      createdAt: new Date().toISOString(),
      status: 'streaming',
      stage: 'sync',
    });

    try {
      const payload = Object.fromEntries(
        Object.entries(editorProfile).map(([key, values]) => [
          key,
          values.filter((item) => item.trim()),
        ]),
      );
      const response = await syncStudentCompetencyResult({
        workspace_conversation_id: conversation.id,
        dify_conversation_id: conversation.difyConversationId,
        profile: payload,
      });
      setProfileState(response.data.profile);
      if (response.data.latest_analysis) {
        setLatestAnalysis(response.data.latest_analysis);
        setActiveGapKey(
          response.data.latest_analysis.priority_gap_dimensions?.[0],
        );
      }
      updateMessage(syncMessageId, (item) => ({
        ...item,
        content: '结果已同步',
        stage: 'sync',
        status: 'completed',
      }));
      pushMessage({
        id: buildId('sync-result'),
        role: 'assistant',
        kind: 'chat',
        content: response.data.assistant_message || '已同步最新解析结果。',
        createdAt: new Date().toISOString(),
        status: 'completed',
      });
      setConversation((current) => ({
        ...current,
        lastMessageId: response.data.last_message_id || current.lastMessageId,
        difyConversationId:
          response.data.dify_conversation_id || current.difyConversationId,
        updatedAt: new Date().toISOString(),
      }));
      setIsEditingResult(false);
      setActiveResultTab('comparison');
      message.success('已保存并同步结果。');
    } catch (error) {
      const detail = extractRequestError(error);
      updateMessage(syncMessageId, (item) => ({
        ...item,
        content: `同步失败：${detail}`,
        stage: 'error',
        status: 'error',
      }));
      message.error(`同步失败：${detail}`);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleCancelEdit = () => {
    setEditorProfile(cloneProfile(currentProfile));
    setIsEditingResult(false);
    setActiveResultTab('comparison');
  };

  const handleToggleCareerFavorite = async () => {
    if (!activeRecommendation) return;
    const favorite = activeRecommendationFavorite;
    const targetKey = buildFavoriteTargetKey(
      activeRecommendation.canonical_job_title,
      activeRecommendation.industry,
    );
    setCareerFavoriteSubmittingKey(targetKey);
    try {
      if (favorite) {
        await deleteCareerDevelopmentFavorite(favorite.favorite_id, {
          skipErrorHandler: true,
        });
        setCareerFavorites((current) =>
          current.filter((item) => item.favorite_id !== favorite.favorite_id),
        );
      } else {
        const response = await createCareerDevelopmentFavorite(
          {
            source_kind: 'recommendation',
            report: activeRecommendation,
          },
          { skipErrorHandler: true },
        );
        setCareerFavorites((current) => {
          const next = current.filter(
            (item) => item.target_key !== response.data.target_key,
          );
          const newFavorite = response.data;
          if (newFavorite?.favorite_id) {
            history.push(
              `/career-development-report/learning-path?favorite_id=${newFavorite.favorite_id}`,
            );
          }
          return [newFavorite, ...next];
        });
      }
    } catch (error) {
      message.error(`收藏失败：${extractRequestError(error)}`);
    } finally {
      setCareerFavoriteSubmittingKey(undefined);
    }
  };

  const careerWorkspace = (
    <CareerMatchWorkspace
      sourceLabel={latestResultMessage?.assetName || '当前12维画像'}
      sourceUpdatedAt={careerMatchInitPayload?.source?.updated_at}
      activeDimensionCount={
        careerMatchInitPayload?.source?.active_dimension_count
      }
      sourceProfile={careerMatchInitPayload?.source?.profile}
      recommendations={recommendationItems}
      loading={careerMatchLoading}
      error={careerMatchError}
      available={careerMatchInitPayload?.available}
      activeRecommendationId={activeRecommendationId}
      activeResultTab={careerActiveResultTab}
      activeGapKey={careerActiveGapKey}
      favorite={activeRecommendationFavorite}
      favoriteSubmitting={
        activeRecommendation
          ? careerFavoriteSubmittingKey ===
            buildFavoriteTargetKey(
              activeRecommendation.canonical_job_title,
              activeRecommendation.industry,
            )
          : false
      }
      onRecommendationChange={setActiveRecommendationId}
      onResultTabChange={setCareerActiveResultTab}
      onActiveGapChange={setCareerActiveGapKey}
      onToggleFavorite={() => void handleToggleCareerFavorite()}
    />
  );

  return (
    <ResumeParsingWorkspace
      activeModule={activeModule}
      onModuleChange={setActiveModule}
      careerWorkspace={careerWorkspace}
      stage={workspaceStage}
      viewState={workspaceViewState}
      conversation={conversation}
      runtimeFields={runtimeFields}
      currentProfile={currentProfile}
      editorProfile={editorProfile}
      tagInputs={tagInputs}
      composerValue={composerValue}
      composerUploads={composerUploads}
      composerError={composerError}
      submitDisabledReason={submitDisabledReason}
      canSubmit={canSubmit}
      isSubmitting={isSubmitting || isSyncing}
      fileUploadEnabled={fileUploadEnabled}
      resultFavorited={resultFavorited}
      analysis={latestAnalysis}
      analysisLoading={analysisLoading}
      activeResultTab={activeResultTab}
      activeGapKey={activeGapKey}
      messagesViewportRef={messagesViewportRef}
      onComposerValueChange={setComposerValue}
      onRemoveUpload={handleRemoveUpload}
      onBeforeUpload={handleBeforeUpload}
      onSubmit={() => void handleSubmit()}
      onTagInputChange={handleTagInputChange}
      onAddTag={handleAddTag}
      onRemoveTag={handleRemoveTag}
      onEdit={handleEdit}
      onSave={() => void handleSave()}
      onCancelEdit={handleCancelEdit}
      onResetConversation={() => void handleResetConversation()}
      onToggleFavorite={() => setResultFavorited((current) => !current)}
      onResultTabChange={(key) => {
        if (isEditingResult && key !== 'result') return;
        setActiveResultTab(key);
      }}
      onActiveGapChange={setActiveGapKey}
    />
  );
};

export default StudentCompetencyProfilePage;

