import { ArrowLeftOutlined, FileSearchOutlined } from '@ant-design/icons';
import { PageContainer } from '@ant-design/pro-components';
import { history } from '@umijs/max';
import {
  Alert,
  Button,
  Card,
  Col,
  Empty,
  Row,
  Skeleton,
  Space,
  Spin,
  Typography,
} from 'antd';
import { createStyles } from 'antd-style';
import React, { useEffect, useState } from 'react';
import { getCareerDevelopmentPlanWorkspace } from '@/services/ant-design-pro/api';
import SnailPhasePanel from './SnailPhasePanel';

const { Text, Title } = Typography;

const useStyles = createStyles(({ css, token }) => ({
  page: css`
    min-height: calc(100vh - 112px);
    background: linear-gradient(180deg, #f7fbff 0%, #ffffff 40%);
  `,
  topBar: css`
    display: flex;
    align-items: center;
