    margin-bottom: 20px;
  `,
  backBtn: css`
    color: ${token.colorPrimary};
    font-size: 13px;
    padding: 0;
    height: auto;
  `,
  hint: css`
    flex: 1;
    color: rgba(18, 49, 77, 0.6);
    font-size: 13px;
  `,
  contentRow: css`
    display: flex;
    gap: 16px;
    align-items: flex-start;
  `,
  mainPanel: css`
    flex: 1;
    min-width: 0;
  `,
  sidePanel: css`
    flex: 0 0 360px;
    max-height: calc(100vh - 200px);
    overflow-y: auto;
    position: sticky;
    top: 12px;
  `,
  heroCard: css`
    border-radius: ${token.borderRadiusLG}px;
    margin-bottom: 16px;
    background: linear-gradient(135deg, #e6f4ff 0%, #ffffff 100%);
    border: 1px solid rgba(22, 119, 255, 0.12);
    box-shadow: 0 8px 24px rgba(31, 56, 88, 0.06);
    :global(.ant-card-body) {
      padding: 20px 24px;
    }
  `,
  heroTitle: css`
    margin: 0 0 8px;
    color: #12314d;
  `,
  heroDesc: css`
    color: rgba(18, 49, 77, 0.72);
    font-size: 13px;
    line-height: 1.8;
    margin: 0;
  `,
  sectionCard: css`
    border-radius: ${token.borderRadiusLG}px;
    margin-bottom: 16px;
    box-shadow: 0 8px 24px rgba(31, 56, 88, 0.06);
    :global(.ant-card-body) {
      padding: 20px 24px;
    }
  `,
  sectionTitle: css`
    margin: 0 0 16px;
    color: #12314d;
    font-size: 15px;
    font-weight: 600;
    display: flex;
    align-items: center;
    gap: 8px;
  `,
  overviewGrid: css`
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 16px;
  `,
  overviewStat: css`
    text-align: center;
    padding: 16px;
    border-radius: 12px;
    background: #f7fbff;
    border: 1px solid rgba(22, 119, 255, 0.08);
  `,
  overviewNum: css`
    font-size: 28px;
    font-weight: 700;
    color: ${token.colorPrimary};
    line-height: 1;
    margin-bottom: 4px;
  `,
  overviewLabel: css`
    font-size: 12px;
    color: rgba(18, 49, 77, 0.6);
  `,
  phaseChip: css`
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 4px 10px;
    border-radius: 999px;
    font-size: 12px;
    font-weight: 600;
    margin-right: 8px;
    margin-bottom: 8px;
  `,
  resourceChips: css`
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    margin-top: 12px;
  `,
  emptyState: css`
    padding: 60px 24px;
    text-align: center;
  `,
}));

const PHASE_COLORS: Record<string, string> = {
  short_term: '#52c41a',
  mid_term: '#faad14',
  long_term: '#8c8c8c',
};

const PHASE_LABELS: Record<string, string> = {
  short_term: '短期',
  mid_term: '中期',
  long_term: '中长期',
};

const LearningPathPage: React.FC = () => {
  const { styles } = useStyles();
  const [workspace, setWorkspace] = useState<API.PlanWorkspacePayload | undefined>();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string>();

  const favoriteId = Number(
    new URLSearchParams(window.location.search).get('favorite_id'),
  );

  useEffect(() => {
    if (!favoriteId || isNaN(favoriteId)) {
      setError('缺少目标 ID，请从职业匹配页面进入');
      return;
    }
    setLoading(true);
    getCareerDevelopmentPlanWorkspace(favoriteId, { skipErrorHandler: true })
      .then((res) => {
        setWorkspace(res?.data);
        if (!res?.data) {
          setError('未找到对应的学习路径数据，请先收藏目标职业');
        }
      })
      .catch((err: any) => {
        if (err?.response?.status === 404) {
          setError('未找到对应的学习路径数据，请先收藏目标职业');
        } else {
          setError(err?.message || '加载失败');
        }
      })
      .finally(() => setLoading(false));
  }, [favoriteId]);

  const favorite = workspace?.favorite;

  // Compute overview stats
  const totalModules =
    workspace?.growth_plan_phases?.reduce(
      (sum, p) => sum + (p.learning_modules?.length || 0),
      0,
    ) || 0;
  const totalMilestones =
    workspace?.growth_plan_phases?.reduce(
      (sum, p) => sum + (p.milestones?.length || 0),
      0,
    ) || 0;

  return (
    <PageContainer>
      <div className={styles.page}>
        {/* Top bar */}
        <div className={styles.topBar}>
          <Button
            type="text"
            icon={<ArrowLeftOutlined />}
            className={styles.backBtn}
            onClick={() => history.back()}
          >
            返回
          </Button>
          <Text className={styles.hint}>
